import React,{useEffect, useRef,useState,useContext} from 'react'
import '../styles/tourdetails.css'
import { Container,Row,Col,Form,ListGroup } from 'reactstrap';
import calculateAvgRating from '../utils/avgrating';
import avatar from '../assets/images/avatar.jpg'
import Booking from '../components/Booking/Booking';
import NewsLetter from '../shared/Newsletter'

import { useParams } from 'react-router-dom';
import useFetch from '../hooks/useFetch';
import { BASE_URL } from '../utils/config';
import { AuthContext } from '../context/AuthContext';
const TourDetails = () => {
  const {id} =useParams();
    const reviewMsgRef=useRef('')
  const [tourRating,setTourRating]=useState(null);

  const {user}=useContext(AuthContext);
  // fetch data from database
   const {data:tour,loading,error}=useFetch(`${BASE_URL}/tours/${id}`)
  //destructure properties from tour object
  const {photo, title, desc, price , reviews, city, distance, maxGroupSize}= tour;
  const {totalRating,avgRating}=calculateAvgRating(reviews);

//format date
  const options={day:'numeric', month:'long', year:'numeric'};

  // submit request to the server
  const submitHandler= async e=>{
    e.preventDefault()
    const reviewText=reviewMsgRef.current.value
   

    try {
      if(!user || user===undefined ||  user===null)
        alert('Please sign in');

      const reviewObj={
      username:user.username,
reviewText,
rating:tourRating
       }
      const res=await fetch(`${BASE_URL}/review/${id}`,{
        method:'post',
        headers:{
          'content-type':'application/json'
        },
        credentials:'include',
        body:JSON.stringify(reviewObj)
      })

     const result= await res.json()
      alert(result.message);
    } catch (error) {
      alert(error.message)
    }
    //later will call our api
  }

  useEffect(()=>{
    window.scrollTo(0,0)
  },[tour])
  return (
    <div>
      <section>
        <Container>
          {
            loading && <h4 className='text-center pt-5'>Loading.....</h4>
          }
           {
            error && <h4 className='text-center pt-5'>{error}</h4>
          }
          {
            !loading && !error  &&  (<Row>
           <Col lg="8">
                 <div className="tour_content">

 
               <img src={photo} alt="" />
                  <div className="tour_info">
                 <h2>{title}</h2>
                    <div className="d-flex align-items-center gap-5">
                     <span className='tour_rating d-flex align-items-center gap-1'>
<i class="ri-star-fill" style={{color:'var(--secondary-color)'}}></i>
{avgRating === 0 ? null :avgRating}

{totalRating === 0 ?(
  'Not rated'
  ) :(  <span>({reviews?.length})</span> ) }
</span>                     
                    </div>

                    <div className="tour_extra-details">
                        <span> <i class="ri-map-pin-fill"></i>{city} </span>
                      <span>  <i class="ri-money-rupees-circle-line"></i>Rs{price}/per person   </span>
                       <span>  <i class="ri-map-pin-time-line"></i>{distance}Km  </span>
                      <span>     <i class="ri-group-line"></i> {maxGroupSize} people</span>
                    </div>
                    <h5>Description </h5>
                     <p>{desc}</p> 
                  </div>


                  {/*--------tour reviews------*/}

                  <div className="tour-reviews mt-4">
                    <h4>Reviews ({reviews?.length} reviews)</h4>

                    <Form onSubmit={submitHandler}>
                      <div className="d-flex align-items-center gap-3 mb-4 rating_group">
                        <span onClick={()=>setTourRating(1)}>1 <i class="ri-star-fill"></i></span>
                        <span onClick={()=>setTourRating(2)}>2 <i class="ri-star-fill"></i></span>
                        <span onClick={()=>setTourRating(3)}>3 <i class="ri-star-fill"></i></span>
                        <span onClick={()=>setTourRating(4)}>4 <i class="ri-star-fill"></i></span>
                        <span onClick={()=>setTourRating(5)}>
                          5 <i class="ri-star-fill"></i></span>

                      </div>

                      <div className="review_input">
                        <input type="text" ref={reviewMsgRef} placeholder='Share your thoughts' required />
                        <button className='btn primary__btn text-white' type='submit'>Submit</button>
                      </div>
                    </Form>
                    <ListGroup className='user_reviews'>
                    {
                      reviews?.map(review=>(
                        <div className="review_item">
                          <img src={avatar} alt="" />

                          <div className="w-100">
                            <div className="d-flex align-items-center justify-content-between">
                              <div>
                                <h5>Ajay</h5>
                                <p>
                                  {new Date('06-15-2024').toLocaleDateString(
                                    'en-US',
                                    options
                                    )} 
                                    </p>
                              </div>
                              <span className='d-flex align-items-center'>
                                5<i class="ri-star-fill" style={{color:'var(--secondary-color)'}}></i>

                              </span>
                            </div>
                            <h6>Amazing tour</h6>
                          </div>
                        </div>
                      ))
                    }
                    </ListGroup>
                  </div>
                 </div>
            </Col>
            <Col lg="4">
            <Booking tour={tour} avgRating={avgRating}/>
            </Col>
          </Row> )
}
        </Container>
      </section>
      <NewsLetter/>
    </div>
  )
}

export default TourDetails
